Here are the public test cases for feature1_price_formatting:
{
  "description": "Formats integer minor-unit amounts into two-decimal major-unit monetary strings using a dot decimal separator.",
  "cases": [
    {
      "input": {
        "feature": "price_formatting",
        "amounts_cents": [
          1000,
          3950,
          1,
          25034
        ]
      },
      "expected_output": "amount_cents=1000\nprice=10.00\namount_cents=3950\nprice=39.50\namount_cents=1\nprice=0.01\namount_cents=25034\nprice=250.34\n"
    }
  ]
}

Here are the public test cases for feature2_checksum:
{
  "description": "Calculates uppercase MD5 checksums for text-like inputs and returns null for inputs that cannot produce a checksum.",
  "cases": [
    {
      "input": {
        "feature": "md5_checksum",
        "mode": "text",
        "value": "foo"
      },
      "expected_output": "mode=text\nchecksum=ACBD18DB4CC2F85CEDEF654FCCC4A4D8\n"
    }
  ]
}

Here are the public test cases for feature3_custom_variables:
{
  "description": "Builds JSON for indexed custom name/value pairs, preserving valid inherited entries, escaping JSON characters, trimming overlong text, and ignoring invalid indexes or malformed value arrays.",
  "cases": [
    {
      "input": {
        "feature": "custom_variables",
        "inherit": false,
        "variables": [
          {
            "index": 1,
            "name": "name",
            "value": "value"
          },
          {
            "index": 2,
            "name": "name2",
            "value": "uńicódę"
          }
        ]
      },
      "expected_output": "custom_variables_json={\"1\":[\"name\",\"value\"],\"2\":[\"name2\",\"uńicódę\"]}\n"
    },
    {
      "input": {
        "feature": "custom_variables",
        "inherit": false,
        "variables": [
          {
            "index": 1,
            "name": "name",
            "value": "value"
          },
          {
            "index": -1,
            "name": "name-1",
            "value": "value"
          }
        ]
      },
      "expected_output": "custom_variables_json={\"1\":[\"name\",\"value\"]}\n"
    }
  ]
}

Here are the public test cases for feature4_custom_dimensions:
{
  "description": "Converts positive, non-empty custom dimension values into numbered output fields, removes null values, ignores zero indexes, and trims overlong values.",
  "cases": [
    {
      "input": {
        "feature": "custom_dimensions",
        "dimensions": [
          {
            "index": 0,
            "value": "foo"
          },
          {
            "index": 1,
            "value": "foo"
          },
          {
            "index": 2,
            "value": "bar"
          },
          {
            "index": 3,
            "value": "empty"
          },
          {
            "index": 3,
            "value": null
          },
          {
            "index": 4,
            "value": ""
          }
        ]
      },
      "expected_output": "dimension_count=2\ndimension1=foo\ndimension2=bar\n"
    }
  ]
}

Here are the public test cases for feature5_ecommerce_items:
{
  "description": "Serializes ecommerce item collections as JSON arrays, formatting prices from cents and supporting item removal and clearing.",
  "cases": [
    {
      "input": {
        "feature": "ecommerce_items",
        "operations": []
      },
      "expected_output": "items_json=[]\n"
    },
    {
      "input": {
        "feature": "ecommerce_items",
        "operations": [
          {
            "action": "add",
            "sku": "fake_sku",
            "name": "fake_product",
            "category": "fake_category",
            "price_cents": 200,
            "quantity": 2
          },
          {
            "action": "add",
            "sku": "fake_sku_2",
            "name": "fake_product_2",
            "category": "fake_category_2",
            "price_cents": 400,
            "quantity": 3
          },
          {
            "action": "clear"
          }
        ]
      },
      "expected_output": "items_json=[]\n"
    }
  ]
}

Here are the public test cases for feature6_track_parameters:
{
  "description": "Stores tracking query parameters as strings, removes parameters set to null or empty strings, preserves first values when requested, and can copy all existing parameters from a base request.",
  "cases": [
    {
      "input": {
        "feature": "track_parameters",
        "operations": [
          {
            "method": "set",
            "param": "h",
            "value": "String"
          }
        ]
      },
      "expected_output": "param_count=1\nh=String\n"
    },
    {
      "input": {
        "feature": "track_parameters",
        "operations": [
          {
            "method": "try_set",
            "param": "h",
            "value": "A"
          },
          {
            "method": "try_set",
            "param": "h",
            "value": "B"
          }
        ]
      },
      "expected_output": "param_count=1\nh=A\n"
    }
  ]
}

Here are the public test cases for feature7_query_encoding:
{
  "description": "Encodes tracking parameters into a URL query string using the public wire keys and UTF-8 escaping.",
  "cases": [
    {
      "input": {
        "feature": "query_encoding",
        "operations": [
          {
            "method": "set",
            "param": "h",
            "value": "abc123"
          }
        ]
      },
      "expected_output": "encoded_query=?h=abc123\n"
    }
  ]
}

Here are the public test cases for feature8_bulk_event_wrapping:
{
  "description": "Groups event query strings into bulk request pages, preserves the base API URL, includes an optional authentication token in JSON payloads, and returns a direct event URL for single-event dispatch.",
  "cases": [
    {
      "input": {
        "feature": "bulk_wrapper",
        "api_url": "http://example.com/",
        "token": "test_token",
        "events": [],
        "action": "summary"
      },
      "expected_output": "has_next=false\nnext_after_end=null\n"
    },
    {
      "input": {
        "feature": "bulk_wrapper",
        "api_url": "http://www.com/java.htm",
        "token": "test_token",
        "events": [
          ""
        ],
        "action": "api_url"
      },
      "expected_output": "api_url=http://www.com/java.htm\n"
    }
  ]
}
